    opacity: 1;
    transform: translateY(0);
  }
}

.card {
  opacity: 0; /* match the 'from' state to prevent flash */
}

.card.visible {
  animation: fadeUp 0.6s ease-out forwards;
}

.card:nth-child(2) { animation-delay: 0.1s; }
.card:nth-child(3) { animation-delay: 0.2s; }

