@keyframes growBar {
  from { width: 0%; }
  to   { width: 100%; }
}

.progress-bar {
  height: 4px;
  background: coral;
  position: fixed;
  top: 0;
  left: 0;
  animation: growBar linear;
  animation-timeline: scroll();
}

/* No JavaScript needed */
/* The scroll position drives the animation progress */

@keyframes fadeUp {
  from { opacity: 0; transform: translateY(40px); }
  to   { opacity: 1; transform: translateY(0); }
}

.card {
  animation: fadeUp ease-out;
  animation-timeline: view();
  animation-range: entry 0% entry 40%;
  /* plays from when element starts entering
     to when 40% of it is in view */
}

